package com.nattechnologies.trastcms.plugins.store; import com.nattechnologies.trastcms.domain.plugin.BundledPluginStateRepository; import com.nattechnologies.trastcms.service.NotFoundException; import org.springframework.stereotype.Component; @Component class StorePluginGuard{private final BundledPluginStateRepository states;StorePluginGuard(BundledPluginStateRepository s){states=s;}void requireEnabled(){if(!states.findById("traststore").map(x->x.isEnabled()).orElse(false))throw new NotFoundException("TrastStore está desactivado");}}
